  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.draft-meta .labels {
  margin: 0;
}

.draft-plan-editor {
  min-width: 0;
  display: grid;
  gap: var(--relay-space-3);
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 3%);
  padding: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.draft-plan-textarea {
  max-width: 100%;
  min-height: 92px;
  resize: vertical;
}

.draft-subtickets {
  min-width: 0;
  display: grid;
  gap: var(--relay-space-2);
}

.draft-subtickets h3 {
  margin: 0;
  font-size: var(--relay-text-base);
  font-weight: 560;
}

.draft-subtickets > p {
  margin: 0;
  color: var(--relay-text-muted);
}

.draft-subticket {
  min-width: 0;
  display: grid;
  gap: var(--relay-space-2);
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 3.5%);
  padding: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.draft-subticket > div:first-child {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--relay-space-2);
}

.draft-subticket strong {
  min-width: 0;
  overflow-wrap: anywhere;
}

.draft-subticket > div:first-child span {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
}

.two-fields {
  min-width: 0;
  display: grid;
  grid-template-columns: 180px 1fr;
  gap: var(--relay-space-3);
}

.markdown-editor {
  min-height: 320px;
  font-family: var(--relay-font-mono);
  line-height: 1.5;
}

  }

  .repository-chat-panel {
    position: fixed;
    inset: 0;
    z-index: 24;
    width: auto;
    height: auto;
    min-width: 0;
    border-left: 0;
  }

  .modal {
    width: calc(100vw - 24px);
    max-height: calc(100dvh - 24px);
