  .create-fields,
  .create-manual-fields,
  .two-fields {
    grid-template-columns: 1fr;
  }

  .status-rail {
    right: 10px;
    bottom: 10px;
    left: 10px;
  }

  .codex-status {
    width: 100%;
  }
}

